// ===== POLA SPA NAVIGATION =====
// Setiap 'halaman' sebenarnya adalah section yang disembunyikan/ditampilkan

// HTML yang dibutuhkan:
// <nav>
//   <a href="#" onclick="navigate('dashboard')">Dashboard</a>
//   <a href="#" onclick="navigate('list')">Daftar Artikel</a>
//   <a href="#" onclick="navigate('add')">Tambah Artikel</a>
// </nav>
// <section id="page-dashboard" class="page">...</section>
// <section id="page-list"      class="page">...</section>
// <section id="page-add"       class="page">...</section>

// CSS:
// .page { display: none; }
// .page.active { display: block; }

// JavaScript:
function navigate(pageName) {
  // Sembunyikan semua halaman
  document.querySelectorAll('.page').forEach(p => p.classList.remove('active'));

  // Tampilkan halaman yang dituju
  const target = document.getElementById(`page-${pageName}`);
  if (target) target.classList.add('active');

  // Update navigasi aktif
  document.querySelectorAll('nav a').forEach(a => a.classList.remove('nav-active'));
  document.querySelector(`[onclick*="'${pageName}'"]`)?.classList.add('nav-active');

  // Refresh data saat masuk halaman list
  if (pageName === 'list') renderTable();
  if (pageName === 'dashboard') updateDashboardStats();
}

// Tampilkan halaman pertama saat load
navigate('dashboard');

// Fungsi untuk menampilkan statistik ringkasan di Dashboard
function updateDashboardStats() {
  const total   = articles.length;
  const thisMonth = articles.filter(a => {
    const date = new Date(a.createdAt.split('/').reverse().join('-'));
    const now  = new Date();
    return date.getMonth() === now.getMonth() &&
           date.getFullYear() === now.getFullYear();
  }).length;

  // Update elemen stat di Dashboard
  const elTotal = document.getElementById('statTotal');
  const elMonth = document.getElementById('statThisMonth');

  if (elTotal) elTotal.textContent = total;
  if (elMonth) elMonth.textContent = thisMonth;
}

